multiple_years_data &lt;- function(years,
                                num_vars = c("AGEP", "PWGTP"),  #AGEP and PWGTP by default
                                cat_vars = c("SEX"), #SEX by default
                                geo = "STATE",       #State by default
                                geo_name = "NC",
                                key = "70c77fa9cc244f5a9fb3c46ed731835d132c0670") {
  df &lt;- NULL
  years &lt;- years[years != 2020]
  for (year in years) {
    year_data &lt;- census_rawdata_to_tibble(
                    single_year_rawdata(year,
                                        num_vars,
                                        cat_vars,
                                        geo,
                                        geo_name,
                                        key)
    )
    year_data$year = year
    if (!(exists("df"))) {
      df &lt;-  year_data
    } else {
      df &lt;-  bind_rows(df, year_data)
    }
  }
  df
}


