plot.census &lt;- function(data, num_var, cat_var) {
  ggplot(
    data,
    aes(
      x = get(cat_var),
      y = get(num_var),
      weight = PWGTP
    )
  ) +
    geom_boxplot() +
    labs(
      x = cat_var,
      y = num_var,
      title = paste(num_var, "by", cat_var)
  ) + 
    theme(
      axis.text.x = element_text(angle = 45, hjust = 1)
  )
}

